<div class="right">
	<NavigationList items={bar} {transformHref} />

	<Search />

	<Menu items={menu} />
</div>

<style>
	:host {
		--wp-admin--admin-bar--position-offset: var(--wp-admin--admin-bar--height, 0px);
		position: sticky;
		top: calc(0px + var(--wp-admin--admin-bar--position-offset, 0px));
		background: var(--shi-navbar-background-color);
		box-shadow: inset 0 -1px 0 0 var(--shi-divider-color);
		width: 100%;
		height: 60px;
		z-index: 1000;
		display: flex;
		align-items: center;
		justify-content: flex-end;
		padding: 0 0 0 12px;
		font-size: 16px;
		box-sizing: border-box;
	}

	.logo-container {
		display: inline-flex;
		align-items: stretch;
		position: absolute;
		left: 12px;
		padding: 0 96px 0 0;
		overflow: hidden;
	}

	.logo-link {
		display: inline-flex;
		align-items: stretch;
		user-select: none;
		background-color: var(--shi-navbar-background-color);
		box-shadow: 32px 0 32px 8px var(--shi-navbar-background-color);
	}

	.right {
		display: flex;
		align-items: stretch;
		gap: 1rem;
		height: 100%;
	}

	@media (width < 600px) {
		.right > :global(.search-wrapper) {
			display: none !important;
		}
	}

	@media (width < 923px) {
		.right > :global(ul.nav-list) {
			display: none !important;
		}
	}
</style>
